import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import Navbar from '../../components/common/Navbar';
import GlassCard from '../../components/common/GlassCard';
import { Calendar, Clock, DollarSign, Star } from 'lucide-react';

const SitterDashboard = () => {
    const { user } = useAuth();
    const [activeTab, setActiveTab] = useState('requests');

    const [requests, setRequests] = useState([]);

    useEffect(() => {
        const fetchReqs = () => {
            const reqs = JSON.parse(localStorage.getItem('booking_requests') || '[]');
            setRequests(reqs.filter(r => r.sitterId === (user?.id || 1)));
        };
        fetchReqs();
        window.addEventListener('storage', fetchReqs);
        return () => window.removeEventListener('storage', fetchReqs);
    }, [user]);

    const handleAction = (id, newStatus) => {
        const reqs = JSON.parse(localStorage.getItem('booking_requests') || '[]');
        const updated = reqs.map(r => r.id === id ? { ...r, status: newStatus } : r);
        localStorage.setItem('booking_requests', JSON.stringify(updated));
        setRequests(updated.filter(r => r.sitterId === (user?.id || 1)));
        window.dispatchEvent(new Event('storage')); // trigger update
    };

    return (
        <div className="min-h-screen bg-background text-on-surface">
            <Navbar />
            <div className="container mx-auto px-4 pt-28 pb-12 flex flex-col md:flex-row gap-8">
                {/* Sidebar */}
                <aside className="w-full md:w-64 flex-shrink-0">
                    <GlassCard className="rounded-[32px] p-6 shadow-xl sticky top-28">
                        <div className="flex flex-col items-center mb-8">
                            <div className="w-24 h-24 rounded-full bg-secondary-fixed flex items-center justify-center text-secondary text-3xl font-bold mb-4">
                                {user?.full_name?.charAt(0) || 'C'}
                            </div>
                            <h2 className="font-display-lg text-xl font-bold text-center">{user?.full_name}</h2>
                            <p className="text-on-surface-variant text-sm text-center">Cuidador Profesional</p>
                        </div>

                        <nav className="flex flex-col gap-2">
                            <button 
                                onClick={() => setActiveTab('requests')}
                                className={`flex items-center gap-3 p-3 rounded-xl transition-all font-bold ${activeTab === 'requests' ? 'bg-primary text-white shadow-md' : 'hover:bg-surface-container'}`}
                            >
                                <Calendar size={20} /> Solicitudes
                            </button>
                            <button 
                                onClick={() => setActiveTab('earnings')}
                                className={`flex items-center gap-3 p-3 rounded-xl transition-all font-bold ${activeTab === 'earnings' ? 'bg-primary text-white shadow-md' : 'hover:bg-surface-container'}`}
                            >
                                <DollarSign size={20} /> Ganancias
                            </button>
                            <button 
                                onClick={() => setActiveTab('profile')}
                                className={`flex items-center gap-3 p-3 rounded-xl transition-all font-bold ${activeTab === 'profile' ? 'bg-primary text-white shadow-md' : 'hover:bg-surface-container'}`}
                            >
                                <Star size={20} /> Editar Perfil
                            </button>
                        </nav>
                    </GlassCard>
                </aside>

                {/* Main Content */}
                <main className="flex-1">
                    {activeTab === 'requests' && (
                        <div>
                            <h2 className="font-display-lg text-3xl font-bold text-primary mb-6">Solicitudes de Cuidado</h2>
                            <div className="space-y-4">
                                {requests.map(req => (
                                    <GlassCard key={req.id} className="rounded-[24px] p-6 shadow-md hover:shadow-lg transition-shadow">
                                        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                                            <div>
                                                <h3 className="font-display-lg text-xl font-bold mb-2">{req.parentName}</h3>
                                                <div className="flex gap-4 text-sm text-on-surface-variant">
                                                    <span className="flex items-center gap-1"><Calendar size={16}/> {req.date}</span>
                                                </div>
                                            </div>
                                            <div className="font-bold text-xl text-primary">${req.total}</div>

                                            <div className="flex gap-2 w-full md:w-auto">
                                                {req.status === 'pending' ? (
                                                    <>
                                                        <button onClick={() => handleAction(req.id, 'accepted')} className="flex-1 md:flex-none bg-primary text-white px-6 py-2 rounded-full font-bold hover:bg-primary-container transition">Aceptar</button>
                                                        <button onClick={() => handleAction(req.id, 'rejected')} className="flex-1 md:flex-none bg-error-container text-on-error-container px-6 py-2 rounded-full font-bold transition hover:bg-error hover:text-white">Rechazar</button>
                                                    </>
                                                ) : (
                                                    <span className="bg-surface-container text-on-surface-variant px-4 py-2 rounded-full text-sm font-bold uppercase">{req.status}</span>
                                                )}
                                            </div>
                                        </div>
                                    </GlassCard>
                                ))}
                            </div>
                        </div>
                    )}

                    {activeTab === 'earnings' && (
                        <div>
                            <h2 className="font-display-lg text-3xl font-bold text-primary mb-6">Mis Ganancias</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
                                <GlassCard className="rounded-[24px] p-6 border-l-4 border-l-primary">
                                    <p className="text-on-surface-variant font-bold mb-2">Balance Disponible</p>
                                    <p className="font-display-lg text-4xl font-bold text-dark">$156.00</p>
                                    <button className="mt-4 bg-primary text-white px-6 py-2 rounded-full text-sm font-bold shadow-md">Solicitar Retiro</button>
                                </GlassCard>
                                <GlassCard className="rounded-[24px] p-6 border-l-4 border-l-secondary">
                                    <p className="text-on-surface-variant font-bold mb-2">Ganancias Históricas</p>
                                    <p className="font-display-lg text-4xl font-bold text-dark">$840.00</p>
                                </GlassCard>
                            </div>
                        </div>
                    )}

                    {activeTab === 'profile' && (
                        <div>
                            <h2 className="font-display-lg text-3xl font-bold text-primary mb-6">Editar Mi Perfil</h2>
                            <GlassCard className="rounded-[32px] p-8 shadow-md">
                                <form className="grid grid-cols-1 md:grid-cols-2 gap-6" onSubmit={(e) => { e.preventDefault(); alert('Perfil guardado exitosamente'); }}>
                                    <div className="md:col-span-2 flex items-center gap-6 mb-4">
                                        <div className="w-24 h-24 rounded-full bg-surface-dim border-2 border-secondary flex items-center justify-center overflow-hidden">
                                            <span className="text-on-surface-variant text-sm text-center px-2">Subir Foto</span>
                                        </div>
                                    </div>
                                    <div><label className="block text-xs font-bold mb-2">Nombre</label><input type="text" className="w-full p-3 rounded-xl bg-surface-container-low" defaultValue={user?.full_name}/></div>
                                    <div><label className="block text-xs font-bold mb-2">Edad</label><input type="number" className="w-full p-3 rounded-xl bg-surface-container-low" placeholder="Ej: 25"/></div>
                                    <div><label className="block text-xs font-bold mb-2">Tarifa por Hora ($)</label><input type="number" className="w-full p-3 rounded-xl bg-surface-container-low" placeholder="Ej: 15"/></div>
                                    <div><label className="block text-xs font-bold mb-2">Años de Experiencia</label><input type="number" className="w-full p-3 rounded-xl bg-surface-container-low" placeholder="Ej: 3"/></div>

                                    <div className="md:col-span-2"><label className="block text-xs font-bold mb-2">Descripción</label><textarea className="w-full p-3 rounded-xl bg-surface-container-low h-20"></textarea></div>

                                    <div className="md:col-span-2"><label className="block text-xs font-bold mb-2">Disponibilidad (Matriz)</label><p className="text-sm text-outline mb-2">Se configurará mediante tabla LUN-DOM interactiva (marcar checkboxes).</p><div className="h-16 bg-surface-container-low rounded-xl flex items-center justify-center border border-dashed border-outline">Hacer clic para editar matriz...</div></div>

                                    <div><label className="block text-xs font-bold mb-2">Carnet de Conducir</label><select className="w-full p-3 rounded-xl bg-surface-container-low"><option>Sí</option><option>No</option></select></div>
                                    <div><label className="block text-xs font-bold mb-2">Coche</label><select className="w-full p-3 rounded-xl bg-surface-container-low"><option>Sí</option><option>No</option></select></div>
                                    <div><label className="block text-xs font-bold mb-2">Fumador</label><select className="w-full p-3 rounded-xl bg-surface-container-low"><option>No</option><option>Sí</option></select></div>
                                    <div><label className="block text-xs font-bold mb-2">Lugar de Trabajo</label><select className="w-full p-3 rounded-xl bg-surface-container-low"><option>En casa de la familia</option><option>En mi casa</option></select></div>

                                    <div className="md:col-span-2"><label className="block text-xs font-bold mb-2">Educación y Certificaciones</label><textarea className="w-full p-3 rounded-xl bg-surface-container-low h-16" placeholder="Ej: Primeros Auxilios, Licenciatura en Pedagogía"></textarea></div>
                                    <div className="md:col-span-2"><label className="block text-xs font-bold mb-2">Superpoderes (Separados por coma)</label><input type="text" className="w-full p-3 rounded-xl bg-surface-container-low" placeholder="Ej: Manualidades, Dibujar, Leer"/></div>
                                    <div className="md:col-span-2"><label className="block text-xs font-bold mb-2">Cómodo con (Separados por coma)</label><input type="text" className="w-full p-3 rounded-xl bg-surface-container-low" placeholder="Ej: Mascotas, Ayuda con tareas, Cocinar"/></div>

                                    <button type="submit" className="md:col-span-2 bg-secondary text-white px-8 py-4 rounded-full font-bold shadow-lg hover:bg-secondary-container transition mt-4">Guardar Perfil</button>
                                </form>
                            </GlassCard>
                        </div>
                    )}
                </main>
            </div>
        </div>
    );
};

export default SitterDashboard;
